// Calculate date range for previous week
const now = new Date();
const lastMonday = new Date(now);
lastMonday.setDate(now.getDate() - 7);
lastMonday.setHours(0, 0, 0, 0);

const lastSunday = new Date(lastMonday);
lastSunday.setDate(lastMonday.getDate() + 6);
lastSunday.setHours(23, 59, 59, 999);

return {
  startDate: lastMonday.toISOString(),
  endDate: lastSunday.toISOString(),
  startDateUnix: Math.floor(lastMonday.getTime() / 1000),
  endDateUnix: Math.floor(lastSunday.getTime() / 1000),
  startDateFormatted: lastMonday.toISOString().split('T')[0],
  endDateFormatted: lastSunday.toISOString().split('T')[0]
};

// Process Twitter data
const items = $input.all();

if (!items || items.length === 0 || !items[0].json.data) {
  return {
    platform: 'Twitter',
    impressions: 0,
    engagements: 0,
    reach: 0,
    engagementRate: 0,
    totalTweets: 0,
    error: null
  };
}

const tweets = items[0].json.data;
let totalImpressions = 0;
let totalEngagements = 0;
let totalRetweets = 0;
let totalLikes = 0;
let totalReplies = 0;

tweets.forEach(tweet => {
  const metrics = tweet.public_metrics || {};
  totalImpressions += metrics.impression_count || 0;
  totalRetweets += metrics.retweet_count || 0;
  totalLikes += metrics.like_count || 0;
  totalReplies += metrics.reply_count || 0;
  totalEngagements += (metrics.retweet_count || 0) + (metrics.like_count || 0) + (metrics.reply_count || 0);
});

const engagementRate = totalImpressions > 0 ? (totalEngagements / totalImpressions * 100).toFixed(2) : 0;

return {
  platform: 'Twitter',
  impressions: totalImpressions,
  engagements: totalEngagements,
  reach: totalImpressions,
  engagementRate: parseFloat(engagementRate),
  totalTweets: tweets.length,
  retweets: totalRetweets,
  likes: totalLikes,
  replies: totalReplies,
  error: null
};

// Process LinkedIn data
const items = $input.all();

if (!items || items.length === 0 || !items[0].json.elements) {
  return {
    platform: 'LinkedIn',
    impressions: 0,
    engagements: 0,
    reach: 0,
    engagementRate: 0,
    totalPosts: 0,
    error: null
  };
}

const elements = items[0].json.elements;
let totalImpressions = 0;
let totalEngagements = 0;
let totalClicks = 0;
let totalLikes = 0;
let totalComments = 0;
let totalShares = 0;
let uniqueReach = 0;

elements.forEach(element => {
  const stats = element.totalShareStatistics || {};
  totalImpressions += stats.impressionCount || 0;
  totalClicks += stats.clickCount || 0;
  totalLikes += stats.likeCount || 0;
  totalComments += stats.commentCount || 0;
  totalShares += stats.shareCount || 0;
  uniqueReach += stats.uniqueImpressionsCount || 0;
  totalEngagements += (stats.clickCount || 0) + (stats.likeCount || 0) + (stats.commentCount || 0) + (stats.shareCount || 0);
});

const engagementRate = totalImpressions > 0 ? (totalEngagements / totalImpressions * 100).toFixed(2) : 0;

return {
  platform: 'LinkedIn',
  impressions: totalImpressions,
  engagements: totalEngagements,
  reach: uniqueReach > 0 ? uniqueReach : totalImpressions,
  engagementRate: parseFloat(engagementRate),
  totalPosts: elements.length,
  clicks: totalClicks,
  likes: totalLikes,
  comments: totalComments,
  shares: totalShares,
  error: null
};

// Aggregate all platform data into summary report
const items = $input.all();
const dateRange = $('Calculate Date Range').item.json;

// Initialize platforms data
const platforms = {
  twitter: null,
  linkedin: null
};

// Extract platform data
items.forEach(item => {
  if (item.json.platform === 'Twitter') {
    platforms.twitter = item.json;
  } else if (item.json.platform === 'LinkedIn') {
    platforms.linkedin = item.json;
  }
});

// Calculate totals
let totalImpressions = 0;
let totalEngagements = 0;
let totalReach = 0;
let platformCount = 0;

const platformDetails = [];

Object.values(platforms).forEach(platform => {
  if (platform && !platform.error) {
    totalImpressions += platform.impressions || 0;
    totalEngagements += platform.engagements || 0;
    totalReach += platform.reach || 0;
    platformCount++;
    platformDetails.push(platform);
  }
});

const overallEngagementRate = totalImpressions > 0 
  ? (totalEngagements / totalImpressions * 100).toFixed(2) 
  : 0;

// Create summary report
const report = {
  reportDate: new Date().toISOString(),
  periodStart: dateRange.startDateFormatted,
  periodEnd: dateRange.endDateFormatted,
  summary: {
    totalImpressions: totalImpressions,
    totalEngagements: totalEngagements,
    totalReach: totalReach,
    overallEngagementRate: parseFloat(overallEngagementRate),
    platformsReported: platformCount
  },
  platforms: platformDetails,
  errors: items.filter(i => i.json.error).map(i => ({
    platform: i.json.platform,
    error: i.json.error
  }))
};

return report;

// Format HTML email report
const report = $input.item.json;

const html = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
    .container { max-width: 800px; margin: 0 auto; padding: 20px; }
    .header { background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); color: white; padding: 30px; border-radius: 10px; text-align: center; }
    .summary { background: #f8f9fa; padding: 20px; border-radius: 8px; margin: 20px 0; }
    .metric { display: inline-block; margin: 10px 20px; text-align: center; }
    .metric-value { font-size: 32px; font-weight: bold; color: #667eea; }
    .metric-label { font-size: 14px; color: #666; }
    .platform { background: white; border: 1px solid #e0e0e0; border-radius: 8px; padding: 20px; margin: 15px 0; }
    .platform-name { font-size: 20px; font-weight: bold; margin-bottom: 15px; }
    .platform-metrics { display: flex; flex-wrap: wrap; gap: 15px; }
    .platform-metric { flex: 1; min-width: 120px; }
    .error { background: #fff3cd; border: 1px solid #ffc107; padding: 15px; border-radius: 5px; margin: 10px 0; }
    table { width: 100%; border-collapse: collapse; margin: 10px 0; }
    td { padding: 8px; border-bottom: 1px solid #eee; }
    td:first-child { font-weight: bold; width: 40%; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>📊 Weekly Social Media Analytics Report</h1>
      <p>Period: ${report.periodStart} to ${report.periodEnd}</p>
    </div>

    <div class="summary">
      <h2>📈 Overall Summary</h2>
      <div style="text-align: center;">
        <div class="metric">
          <div class="metric-value">${report.summary.totalImpressions.toLocaleString()}</div>
          <div class="metric-label">Total Impressions</div>
        </div>
        <div class="metric">
          <div class="metric-value">${report.summary.totalEngagements.toLocaleString()}</div>
          <div class="metric-label">Total Engagements</div>
        </div>
        <div class="metric">
          <div class="metric-value">${report.summary.totalReach.toLocaleString()}</div>
          <div class="metric-label">Total Reach</div>
        </div>
        <div class="metric">
          <div class="metric-value">${report.summary.overallEngagementRate}%</div>
          <div class="metric-label">Engagement Rate</div>
        </div>
      </div>
    </div>

    <h2>🔍 Platform Breakdown</h2>

    ${report.platforms.map(platform => `
      <div class="platform">
        <div class="platform-name">${platform.platform === 'Twitter' ? '🐦 Twitter' : platform.platform === 'LinkedIn' ? '💼 LinkedIn' : platform.platform}</div>
        <table>
          <tr><td>Impressions</td><td>${platform.impressions.toLocaleString()}</td></tr>
          <tr><td>Engagements</td><td>${platform.engagements.toLocaleString()}</td></tr>
          <tr><td>Reach</td><td>${platform.reach.toLocaleString()}</td></tr>
          <tr><td>Engagement Rate</td><td>${platform.engagementRate}%</td></tr>
          ${platform.totalTweets ? `<tr><td>Total Tweets</td><td>${platform.totalTweets}</td></tr>` : ''}
          ${platform.totalPosts ? `<tr><td>Total Posts</td><td>${platform.totalPosts}</td></tr>` : ''}
          ${platform.retweets ? `<tr><td>Retweets</td><td>${platform.retweets.toLocaleString()}</td></tr>` : ''}
          ${platform.likes ? `<tr><td>Likes</td><td>${platform.likes.toLocaleString()}</td></tr>` : ''}
          ${platform.clicks ? `<tr><td>Clicks</td><td>${platform.clicks.toLocaleString()}</td></tr>` : ''}
          ${platform.shares ? `<tr><td>Shares</td><td>${platform.shares.toLocaleString()}</td></tr>` : ''}
        </table>
      </div>
    `).join('')}

    ${report.errors && report.errors.length > 0 ? `
      <div class="error">
        <h3>⚠️ Errors Encountered</h3>
        ${report.errors.map(e => `<p><strong>${e.platform}:</strong> ${e.error}</p>`).join('')}
      </div>
    ` : ''}

    <p style="margin-top: 30px; color: #666; font-size: 12px; text-align: center;">
      Report generated on ${new Date(report.reportDate).toLocaleString()}<br>
      Automated by n8n Workflow
    </p>
  </div>
</body>
</html>
`;

return {
  html: html,
  subject: `📊 Weekly Social Media Report: ${report.periodStart} - ${report.periodEnd}`,
  report: report
};

// Error handler for Twitter
const error = $input.item.error;

return {
  platform: 'Twitter',
  impressions: 0,
  engagements: 0,
  reach: 0,
  engagementRate: 0,
  totalTweets: 0,
  error: error ? error.message : 'Failed to fetch Twitter data'
};

// Error handler for LinkedIn
const error = $input.item.error;

return {
  platform: 'LinkedIn',
  impressions: 0,
  engagements: 0,
  reach: 0,
  engagementRate: 0,
  totalPosts: 0,
  error: error ? error.message : 'Failed to fetch LinkedIn data'
};
